import{_ as t,o as a,c as i,a0 as s}from"./chunks/framework.B_R3rS_4.js";const p=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),o={name:"guide/getting-started.md"};function n(l,e,r,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>The Modern RTI Viewer is a complete rewrite of the traditional <code>spidergl</code> based RTI viewers, leveraging the power of Vue 3 and Three.js.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>If you are a developer looking to build or run the project locally:</p><ol><li><p><strong>Install dependencies:</strong> Make sure you have Node.js and <code>pnpm</code> installed.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div></li><li><p><strong>Run the Development Server:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>This will spin up a Vite development server (usually at <code>http://localhost:5173</code>).</p></li></ol><h2 id="usage-instructions" tabindex="-1">Usage Instructions <a class="header-anchor" href="#usage-instructions" aria-label="Permalink to &quot;Usage Instructions&quot;">​</a></h2><p>The viewer loads an RTI dataset via a URL property pointing to a directory that contains an <code>info.xml</code> file and the hierarchical image tiles.</p><h3 id="interface-modes" tabindex="-1">Interface Modes <a class="header-anchor" href="#interface-modes" aria-label="Permalink to &quot;Interface Modes&quot;">​</a></h3><p>The viewer provides several interaction modes on the left sidebar:</p><ol><li><p><strong>Pan &amp; Zoom (Hand Icon):</strong></p><ul><li>Click and drag anywhere on the canvas to pan across the image.</li><li>Use the scroll wheel (or pinch gesture on trackpads) to zoom in and out.</li><li>The quadtree LOD system will automatically load high-resolution tiles as you zoom in.</li></ul></li><li><p><strong>Light Direction (Lightbulb Icon):</strong></p><ul><li>Click and drag on the main canvas to interactively change the lighting angle.</li><li>The lighting simulation uses the RTI coefficients (PTM or HSH) to dynamically compute shadows and highlights.</li><li><strong>Compass Widget:</strong> The widget in the bottom left provides a visual reference of the current light position (x, y). You can also drag the dot inside the compass to move the light.</li></ul></li></ol><h3 id="render-modes" tabindex="-1">Render Modes <a class="header-anchor" href="#render-modes" aria-label="Permalink to &quot;Render Modes&quot;">​</a></h3><p>You can switch the mathematical rendering mode:</p><ul><li><strong>Default Mode:</strong> Computes the standard diffuse reflection based on the encoded RTI coefficients.</li><li><strong>Specular Enhancement:</strong> Adds an artificial specular highlight on top of the diffuse lighting to enhance surface details and scratches.</li><li><strong>Normals:</strong> Visualizes the surface normal vectors calculated directly from the RTI coefficients, allowing you to see the raw geometric shape without texture color.</li><li><strong>Slope Heatmap:</strong> Computes the steepness of the surface and maps it to a color gradient (blue for flat, red for steep). Extremely useful for highlighting shallow engravings or scratches without adjusting the light.</li><li><strong>Dual Light:</strong> Calculates a secondary, opposite light source (raking light). The primary light is tinted red and the opposing light blue. This creates high-contrast shadows that perfectly reveal fine tool marks and edges.</li></ul>',13)])])}const u=t(o,[["render",n]]);export{p as __pageData,u as default};
